/**
 * Dynamic tool execution.
 * Executes HTTP API calls defined in the `tools` table,
 * with body generated by the LLM via function calling.
 */

/**
 * Build a tool definition for function calling from a DB tool row.
 * @param {Object} tool - Tool row from the `tools` table
 * @returns {Object} Tool definition compatible with LLM function calling
 */
export function buildToolDef(tool) {
  // Build parameters schema from body_schema
  let parametersSchema = { type: 'object', properties: {} }

  if (tool.body_schema) {
    try {
      const schema = typeof tool.body_schema === 'string'
        ? JSON.parse(tool.body_schema)
        : tool.body_schema
      parametersSchema = {
        type: 'object',
        properties: {
          body: {
            type: 'object',
            description: `Generate JSON matching this schema: ${JSON.stringify(schema)}`,
            properties: schema.properties || schema,
          },
        },
      }
    } catch {
      // If body_schema is not parseable, use empty
    }
  }

  return {
    name: `api_tool_${tool.id}`,
    description: tool.description || `Call the ${tool.name} API`,
    parameters: parametersSchema,
  }
}

/**
 * Execute a dynamic tool call (HTTP request).
 * @param {Object} tool - Tool row from the `tools` table
 * @param {Object} params - Parameters generated by the LLM
 * @returns {Promise<string>} Response body as string
 */
export async function executeTool(tool, params) {
  const method = (tool.method || 'GET').toUpperCase()
  let url = tool.url

  // Apply query parameters
  if (tool.query_parameters) {
    const qp = typeof tool.query_parameters === 'string'
      ? JSON.parse(tool.query_parameters)
      : tool.query_parameters
    const searchParams = new URLSearchParams()
    for (const [key, value] of Object.entries(qp)) {
      if (value !== null && value !== undefined) {
        searchParams.append(key, value)
      }
    }
    const qs = searchParams.toString()
    if (qs) url += (url.includes('?') ? '&' : '?') + qs
  }

  // Build headers
  const headers = { 'Content-Type': 'application/json' }
  if (tool.headers) {
    const h = typeof tool.headers === 'string' ? JSON.parse(tool.headers) : tool.headers
    Object.assign(headers, h)
  }

  // Build fetch options
  const fetchOpts = { method, headers }

  // Add body for non-GET requests
  if (method !== 'GET' && method !== 'HEAD') {
    const body = params?.body || params || {}
    fetchOpts.body = JSON.stringify(body)
  }

  try {
    const response = await fetch(url, fetchOpts)
    const text = await response.text()

    if (!response.ok) {
      return `API Error (${response.status}): ${text.slice(0, 500)}`
    }

    // Try to parse JSON for cleaner output
    try {
      const json = JSON.parse(text)
      return JSON.stringify(json, null, 2).slice(0, 2000)
    } catch {
      return text.slice(0, 2000)
    }
  } catch (err) {
    return `Tool execution error: ${err.message}`
  }
}
